package org.apache.commons.csv;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.File;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.lang.reflect.Method;
import java.nio.charset.Charset;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.forName("UTF-8");
    }

    @Test
    void testPrint_FileAndCharset_Success() throws IOException {
        // Since CSVPrinter constructor uses OutputStreamWriter(new FileOutputStream(out), charset)
        // We can't mock FileOutputStream easily without PowerMock or similar, so we test with temp file.
        File tempFile = File.createTempFile("csvformattest", ".csv");
        tempFile.deleteOnExit();

        CSVPrinter printer = csvFormat.print(tempFile, charset);
        assertNotNull(printer);
        printer.close();
    }

    @Test
    void testPrint_FileAndCharset_IOException() {
        // Use a File that is a directory to provoke IOException on FileOutputStream
        File dir = new File(System.getProperty("java.io.tmpdir"));
        assertTrue(dir.isDirectory());

        assertThrows(IOException.class, () -> csvFormat.print(dir, charset));
    }

    @Test
    void testPrint_PrivatePrintMethod_Reflection() throws Exception {
        // Use reflection to invoke private print method:
        // private void print(final Object object, final CharSequence value, final int offset, final int len,
        //            final Appendable out, final boolean newRecord)

        Method privatePrintMethod = CSVFormat.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class, Appendable.class, boolean.class);
        privatePrintMethod.setAccessible(true);

        StringBuilder out = new StringBuilder();

        // Test with null object and null CharSequence, offset 0, len 0, newRecord false
        privatePrintMethod.invoke(csvFormat, null, null, 0, 0, out, false);
        assertEquals("", out.toString());

        // Test with object and CharSequence with offset and length
        String testValue = "value123";
        privatePrintMethod.invoke(csvFormat, "obj", testValue, 0, testValue.length(), out, true);
        // The output should contain the string value printed (quoted or escaped depends on CSVFormat)
        assertTrue(out.length() > 0);

        // Test with offset and len smaller than string length
        out.setLength(0);
        privatePrintMethod.invoke(csvFormat, "obj", testValue, 1, 3, out, false);
        assertTrue(out.length() > 0);

        // Test with newRecord true to check line separator appended
        out.setLength(0);
        privatePrintMethod.invoke(csvFormat, "obj", testValue, 0, testValue.length(), out, true);
        assertTrue(out.toString().endsWith(csvFormat.getRecordSeparator()));
    }

    @Test
    void testPrintAndEscape_PrivateMethod_Reflection() throws Exception {
        Method printAndEscapeMethod = CSVFormat.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class, Appendable.class);
        printAndEscapeMethod.setAccessible(true);

        StringBuilder out = new StringBuilder();

        // Normal string
        printAndEscapeMethod.invoke(csvFormat, "abc,def", 0, 7, out);
        assertTrue(out.length() > 0);

        // Empty string
        out.setLength(0);
        printAndEscapeMethod.invoke(csvFormat, "", 0, 0, out);
        assertEquals(0, out.length());

        // Substring
        out.setLength(0);
        printAndEscapeMethod.invoke(csvFormat, "abcdef", 2, 3, out);
        assertTrue(out.length() > 0);
    }

    @Test
    void testPrintAndQuote_PrivateMethod_Reflection() throws Exception {
        Method printAndQuoteMethod = CSVFormat.class.getDeclaredMethod("printAndQuote", Object.class, CharSequence.class, int.class, int.class, Appendable.class, boolean.class);
        printAndQuoteMethod.setAccessible(true);

        StringBuilder out = new StringBuilder();

        // Test with normal string and newRecord false
        printAndQuoteMethod.invoke(csvFormat, "obj", "quotedValue", 0, 11, out, false);
        assertTrue(out.length() > 0);

        // Test with newRecord true
        out.setLength(0);
        printAndQuoteMethod.invoke(csvFormat, "obj", "quotedValue", 0, 11, out, true);
        assertTrue(out.toString().endsWith(csvFormat.getRecordSeparator()));

        // Test with null CharSequence
        out.setLength(0);
        printAndQuoteMethod.invoke(csvFormat, "obj", null, 0, 0, out, false);
        assertTrue(out.length() > 0);
    }
}
